sql:
SELECT monthly_listeners 
FROM listener_stats 
WHERE artist_id = 0;

SELECT
    (SELECT AVG(monthly_listeners) 
     FROM artists 
     WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'United Kingdom')
    ) AS average_monthly_listeners,
    (SELECT total_streams 
     FROM artists 
     WHERE artist_name = 'Joji'
    ) AS total_streams;

SELECT AVG(monthly_listeners) AS AverageMonthlyListeners
FROM artists
WHERE country_id = (SELECT country_id FROM countries WHERE country_name = 'United Kingdom');

SELECT artists.artist_name, listener_stats.monthly_listeners 
FROM artists 
JOIN listener_stats ON artists.artist_id = listener_stats.artist_id;

SELECT artists.artist_name, streaks.current_weekly_streak 
FROM artists 
JOIN streaks ON artists.artist_id = streaks.artist_id 
WHERE streaks.current_weekly_streak = (
    SELECT MAX(current_weekly_streak) FROM streaks
);

SELECT artists.artist_name, countries.country_name, artists.monthly_listeners
FROM artists
JOIN countries ON artists.country_id = countries.country_id;
